mapper.select:
SELECT * FROM archive_document
WHERE archive_id = #{archiveId}
ORDER BY sort_order, upload_time DESC

mapper.update:
UPDATE archive_document SET
    document_name = #{documentName},
    description = #{description},
    sort_order = #{sortOrder}
WHERE id = #{id}

mapper.select:
SELECT * FROM archive_document
WHERE archive_id = #{archiveId} AND document_type = #{documentType}
ORDER BY upload_time DESC
